const parseFrontmatter = (raw) => {
	const match = raw.match(/^---\r?\n([\s\S]*?)\r?\n---\r?\n?([\s\S]*)$/);
	if (!match) return {
		data: {},
		content: raw
	};
	const parsed = parse(match[1] ?? "");
	return {
		data: isPlainObject(parsed) ? parsed : {},
		content: match[2] ?? ""
	};
};
