//#region src/utils/sanitize-name.ts
const sanitizeName = (name) => {
	return name.toLowerCase().replace(/[^a-z0-9._]+/g, "-").replace(/^[.-]+|[.-]+$/g, "").substring(0, 255) || "unnamed-skill";
};
